html.head:
/* Root Colors */
:root {
--primary-color: #e50914;
--secondary-color: #221f1f;
--text-color: #ffffff;
--card-bg: #2f2f2f;
--border-color: #404040;
--hover-bg: #3a3a3a;
--accent-color: #ffc107;
--rating-color: #ff9800;
}

/* Global Styles */
* {
margin: 0;
padding: 0;
box-sizing: border-box;
}

body {
background-color: #221f1f;
color: #ffffff;
font-family: 'Arial', sans-serif;
line-height: 1.6;
overflow-x: hidden;
}

html, body {
width: 100%;
height: 100%;
}

/* Navbar */
#header-wrapper {
background: linear-gradient(135deg, rgba(34,31,31,0.95) 0%, rgba(20,20,20,0.98) 100%);
padding: 1rem 0;
position: sticky;
top: 0;
z-index: 1000;
box-shadow: 0 4px 15px rgba(0,0,0,0.3);
border-bottom: 2px solid #e50914;
}

#header h1 {
color: #e50914;
font-size: 2rem;
margin: 0;
padding: 0.5rem 0;
}

#header h1 a {
color: #e50914;
text-decoration: none;
}

#header h1 a:hover {
color: #ffc107;
}

#header-inner {
padding: 0 20px;
}

.description {
color: #999;
font-size: 0.9rem;
display: none;
}

/* Blog Title */
#blog-title {
font-size: 2rem;
color: #e50914;
}

/* Main Wrapper */
#main-wrapper {
background: #221f1f;
}

.content-outer {
background: transparent;
}

/* Posts */
.post {
background: #2f2f2f;
border-radius: 8px;
padding: 1.5rem;
margin-bottom: 2rem;
box-shadow: 0 4px 15px rgba(0,0,0,0.3);
border: 1px solid #404040;
}

.post-title {
color: #e50914;
font-size: 1.5rem;
margin-bottom: 0.5rem;
}

.post-title a {
color: #e50914;
text-decoration: none;
}

.post-title a:hover {
color: #ffc107;
}

.post-meta {
color: #999;
font-size: 0.9rem;
margin-bottom: 1rem;
}

.post-body {
color: #fff;
line-height: 1.8;
}

.post-body img {
max-width: 100%;
height: auto;
border-radius: 8px;
margin: 1rem 0;
}

/* Sidebar */
#sidebar-wrapper {
background: transparent;
}

.sidebar-content {
background: transparent;
}

.widget {
background: #2f2f2f;
border-radius: 8px;
padding: 1.5rem;
margin-bottom: 1.5rem;
border: 1px solid #404040;
box-shadow: 0 4px 15px rgba(0,0,0,0.3);
}

.widget h2 {
color: #e50914;
font-size: 1.2rem;
margin-bottom: 1rem;
border-bottom: 2px solid #e50914;
padding-bottom: 0.5rem;
}

.widget ul {
list-style: none;
}

.widget li {
padding: 0.5rem 0;
border-bottom: 1px solid #404040;
}

.widget li:last-child {
border-bottom: none;
}

.widget a {
color: #fff;
text-decoration: none;
transition: all 0.3s ease;
}

.widget a:hover {
color: #e50914;
padding-left: 0.5rem;
}

/* Footer */
#footer-wrapper {
background: linear-gradient(135deg, rgba(34,31,31,0.95) 0%, rgba(20,20,20,0.98) 100%);
color: #fff;
padding: 2rem 0 1rem;
border-top: 2px solid #e50914;
text-align: center;
}

#footer h2 {
color: #e50914;
font-size: 1.2rem;
margin-bottom: 1rem;
}

#footer a {
color: #999;
text-decoration: none;
}

#footer a:hover {
color: #e50914;
}

/* Responsive */
@media (max-width: 768px) {
#header h1 {
font-size: 1.5rem;
}

.post {
padding: 1rem;
}

.post-title {
font-size: 1.2rem;
}

.widget {
padding: 1rem;
}

#main-wrapper {
margin: 0;
}
}

/* Links */
a {
color: #e50914;
text-decoration: none;
}

a:hover {
color: #ffc107;
}

/* Buttons */
.button {
background: #e50914;
color: white;
padding: 0.5rem 1rem;
border-radius: 4px;
border: none;
cursor: pointer;
transition: all 0.3s ease;
}

.button:hover {
background: #c20812;
}

/* Labels */
.label {
display: inline-block;
background: #e50914;
color: white;
padding: 0.25rem 0.75rem;
border-radius: 4px;
margin: 0.25rem;
font-size: 0.85rem;
}

/* Comments */
#comments {
background: #2f2f2f;
border-radius: 8px;
padding: 1.5rem;
border: 1px solid #404040;
}

.comment {
background: #3a3a3a;
padding: 1rem;
margin-bottom: 1rem;
border-radius: 4px;
border-left: 3px solid #e50914;
}

.comment-author {
color: #e50914;
font-weight: bold;
}

.comment-date {
color: #999;
font-size: 0.85rem;
}






<meta content='' name='description'/>

body.script:
// Back to Top functionality
var backToTopBtn = document.getElementById("backToTopBtn");

window.onscroll = function() {
if (document.body.scrollTop > 300 || document.documentElement.scrollTop > 300) {
backToTopBtn.style.display = "flex";
} else {
backToTopBtn.style.display = "none";
}
};

function topFunction() {
document.body.scrollTop = 0;
document.documentElement.scrollTop = 0;
}

// Smooth scroll
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
anchor.addEventListener('click', function (e) {
e.preventDefault();
var target = document.querySelector(this.getAttribute('href'));
if (target) {
target.scrollIntoView({
behavior: 'smooth'
});
}
});
});
